import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeDocument = async (text: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze the following document and provide a structured summary including key insights, threat levels, and an assessment of any technical permissions mentioned. 

    Document:
    ${text}
    `,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          keyInsights: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          },
          threatLevel: { 
            type: Type.STRING, 
            description: "Assess as Low, Medium, High, or Critical" 
          },
          permissions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                risk: { type: Type.STRING }
              }
            }
          }
        },
        required: ["summary", "keyInsights", "threatLevel", "permissions"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    return null;
  }
};

export const chatWithDoc = async (history: { role: 'user' | 'model', parts: { text: string }[] }[], query: string, context: string) => {
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: `You are the Sentient-X Intelligence Officer. You are an expert in the provided National Security Architecture document. Answer all questions with high precision, professional tone, and tactical insight. Use data from the document: ${context.slice(0, 10000)}`
    }
  });

  const result = await chat.sendMessage({ message: query });
  return result.text;
};

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { ArchitectureNode, ArchitectureLink } from '../types';

interface NetworkGraphProps {
  nodes: ArchitectureNode[];
  links: ArchitectureLink[];
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ nodes, links }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current || nodes.length === 0) return;

    const width = svgRef.current.clientWidth;
    const height = svgRef.current.clientHeight;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const simulation = d3.forceSimulation<ArchitectureNode>(nodes)
      .force("link", d3.forceLink<ArchitectureNode, ArchitectureLink>(links).id(d => d.id).distance(100))
      .force("charge", d3.forceManyBody().strength(-300))
      .force("center", d3.forceCenter(width / 2, height / 2));

    const link = svg.append("g")
      .attr("stroke", "#334155")
      .attr("stroke-opacity", 0.6)
      .selectAll("line")
      .data(links)
      .join("line")
      .attr("stroke-width", d => Math.sqrt(d.value));

    const node = svg.append("g")
      .attr("stroke", "#0f172a")
      .attr("stroke-width", 1.5)
      .selectAll("circle")
      .data(nodes)
      .join("circle")
      .attr("r", 8)
      .attr("fill", d => d.group === 1 ? "#06b6d4" : d.group === 2 ? "#10b981" : "#f43f5e")
      .call(d3.drag<SVGCircleElement, ArchitectureNode>()
        .on("start", dragstarted)
        .on("drag", dragged)
        .on("end", dragended));

    node.append("title").text(d => d.label);

    const labels = svg.append("g")
      .selectAll("text")
      .data(nodes)
      .join("text")
      .text(d => d.label)
      .attr("font-size", "10px")
      .attr("fill", "#94a3b8")
      .attr("dx", 12)
      .attr("dy", 4);

    simulation.on("tick", () => {
      link
        .attr("x1", d => (d.source as any).x)
        .attr("y1", d => (d.source as any).y)
        .attr("x2", d => (d.target as any).x)
        .attr("y2", d => (d.target as any).y);

      node
        .attr("cx", d => (d as any).x)
        .attr("cy", d => (d as any).y);

      labels
        .attr("x", d => (d as any).x)
        .attr("y", d => (d as any).y);
    });

    function dragstarted(event: any) {
      if (!event.active) simulation.alphaTarget(0.3).restart();
      event.subject.fx = event.subject.x;
      event.subject.fy = event.subject.y;
    }

    function dragged(event: any) {
      event.subject.fx = event.x;
      event.subject.fy = event.y;
    }

    function dragended(event: any) {
      if (!event.active) simulation.alphaTarget(0);
      event.subject.fx = null;
      event.subject.fy = null;
    }

    return () => {
      simulation.stop();
    };
  }, [nodes, links]);

  return (
    <div className="w-full h-full bg-slate-900/50 rounded-xl overflow-hidden border border-slate-800">
      <svg ref={svgRef} className="w-full h-full" />
    </div>
  );
};

export default NetworkGraph;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { analyzeDocument, chatWithDoc } from './services/geminiService';
import NetworkGraph from './components/NetworkGraph';
import { ArchitectureNode, ArchitectureLink, DocumentAnalysis, Message } from './types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

// Minimalistic but functional mock data for the initial render
const INITIAL_NODES: ArchitectureNode[] = [
