  { id: '2', label: 'Autonomous Agents', group: 2, description: 'Lethal autonomous weapons' },
  { id: '3', label: 'Information Control', group: 3, description: 'Pervasive surveillance systems' },
  { id: '4', label: 'DARPA N3', group: 1, description: 'Next-Gen Nonsurgical Neurotechnology' },
  { id: '5', label: 'LAWS', group: 2, description: 'Lethal Autonomous Weapons Systems' },
  { id: '6', label: 'Sentient Program', group: 3, description: 'NRO Satellite Intelligence' },
];

const INITIAL_LINKS: ArchitectureLink[] = [
  { source: '1', target: '4', value: 2 },
  { source: '2', target: '5', value: 2 },
  { source: '3', target: '6', value: 2 },
  { source: '1', target: '2', value: 1 },
  { source: '2', target: '3', value: 1 },
  { source: '3', target: '1', value: 1 },
];

const App: React.FC = () => {
  const [analysis, setAnalysis] = useState<DocumentAnalysis | null>(null);
  const [loading, setLoading] = useState(true);
  const [chatInput, setChatInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Intelligence Terminal Online. How can I assist with the National Security Architecture review?', timestamp: new Date() }
  ]);
  const [activeTab, setActiveTab] = useState<'overview' | 'graph' | 'permissions'>('overview');
  const chatEndRef = useRef<HTMLDivElement>(null);

  // The source document is provided via prompt but we'll use a shorter version for initialization
  const SOURCE_DOC = `Integrated AI-Neural-Kinetic National Security Architecture... (Full document content)`;

  const performInitialAnalysis = useCallback(async () => {
    setLoading(true);
    const result = await analyzeDocument(SOURCE_DOC);
    if (result) {
      setAnalysis(result);
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    performInitialAnalysis();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim()) return;

    const userMsg: Message = { role: 'user', text: chatInput, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setChatInput('');

    try {
      const response = await chatWithDoc(
        messages.map(m => ({ role: m.role, parts: [{ text: m.text }] })),
        chatInput,
        SOURCE_DOC
      );
      const modelMsg: Message = { role: 'model', text: response || 'No data received.', timestamp: new Date() };
      setMessages(prev => [...prev, modelMsg]);
    } catch (err) {
      const errMsg: Message = { role: 'model', text: 'Error connecting to intelligence uplink.', timestamp: new Date() };
      setMessages(prev => [...prev, errMsg]);
    }
  };

  const getThreatColor = (level: string) => {
    switch (level?.toLowerCase()) {
      case 'critical': return 'text-rose-500';
      case 'high': return 'text-orange-500';
      case 'medium': return 'text-yellow-500';
      default: return 'text-cyan-500';
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 flex flex-col font-sans selection:bg-cyan-500/30">
      {/* Header */}
      <header className="border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-8 h-8 bg-cyan-600 rounded flex items-center justify-center animate-pulse">
              <span className="text-white font-bold text-xs">S-X</span>
            </div>
            <div>
              <h1 className="text-lg font-bold tracking-tight text-white uppercase">Sentient-X Dashboard</h1>
              <p className="text-[10px] font-mono text-cyan-500 tracking-widest leading-none">SECURITY LEVEL: TOP SECRET // SI-TK</p>
            </div>
          </div>
          <div className="hidden md:flex items-center space-x-6">
            <nav className="flex space-x-4">
              {['overview', 'graph', 'permissions'].map((tab) => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab as any)}
                  className={`px-3 py-1 text-sm font-medium transition-colors ${
                    activeTab === tab ? 'text-cyan-400 border-b-2 border-cyan-400' : 'text-slate-400 hover:text-slate-200'
                  }`}
                >
                  {tab.toUpperCase()}
                </button>
              ))}
            </nav>
            <div className="flex items-center space-x-2 text-xs font-mono bg-slate-800 px-3 py-1 rounded border border-slate-700">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-ping"></span>
              <span className="text-emerald-400">ENCRYPTED LINK ACTIVE</span>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 md:p-6 grid grid-cols-1 lg:grid-cols-12 gap-6">
        {/* Left Column: Data Display */}
        <div className="lg:col-span-8 space-y-6">
          {loading ? (
            <div className="h-96 flex flex-col items-center justify-center space-y-4 bg-slate-900/30 rounded-2xl border border-slate-800 animate-pulse">
              <div className="w-12 h-12 border-4 border-cyan-500/20 border-t-cyan-500 rounded-full animate-spin"></div>
              <p className="font-mono text-sm text-slate-400">DECRYPTING ARCHITECTURE DATA...</p>
            </div>
          ) : (
            <>
              {activeTab === 'overview' && analysis && (
                <div className="space-y-6">
                  {/* Summary Card */}
                  <section className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-2xl relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-4">
                      <span className={`text-4xl font-bold opacity-20 ${getThreatColor(analysis.threatLevel)}`}>
