                  {/* Android Component Specs (Based on Prompt) */}
                  <section className="bg-slate-900 border border-slate-800 rounded-2xl p-6 shadow-2xl">
                    <h2 className="text-xl font-bold mb-4 flex items-center text-white">
                      <span className="mr-2 text-emerald-500">▶</span> MOBILE INFRASTRUCTURE SPECS
                    </h2>
                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 font-mono text-[10px]">
                      <div className="p-3 bg-slate-800 rounded border border-slate-700">
                        <p className="text-slate-500 uppercase mb-1">Device Model</p>
                        <p className="text-white text-xs">Moto G 2025 (XT2513-1)</p>
                      </div>
                      <div className="p-3 bg-slate-800 rounded border border-slate-700">
                        <p className="text-slate-500 uppercase mb-1">Android Vers.</p>
                        <p className="text-white text-xs">16.01.000</p>
                      </div>
                      <div className="p-3 bg-slate-800 rounded border border-slate-700">
                        <p className="text-slate-500 uppercase mb-1">IPv6 Address</p>
                        <p className="text-cyan-400 text-[9px] truncate">2607:fb91:1bab:1232:ad3:f457:4f31:5b5f</p>
                      </div>
                      <div className="p-3 bg-slate-800 rounded border border-slate-700">
                        <p className="text-slate-500 uppercase mb-1">Hardware ID</p>
                        <p className="text-white text-xs">ZT4224S9LN</p>
                      </div>
                    </div>
                  </section>
                </div>
              )}

              {activeTab === 'graph' && (
                <div className="h-[600px] flex flex-col space-y-4">
                   <div className="flex-1 relative">
                      <NetworkGraph nodes={INITIAL_NODES} links={INITIAL_LINKS} />
                      <div className="absolute bottom-4 left-4 flex space-x-4 bg-slate-900/80 p-2 rounded border border-slate-800 text-[10px] font-mono">
