import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeDocument = async (text: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze the following document and provide a structured summary. 
    Crucially, for every technical permission mentioned (like Android manifest permissions), provide a detailed risk rationale explaining the threat vector it enables within this national security context.

    Document:
    ${text}
    `,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          keyInsights: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          },
          threatLevel: { 
            type: Type.STRING, 
            description: "Assess as Low, Medium, High, or Critical" 
          },
          permissions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                risk: { type: Type.STRING },
                rationale: { type: Type.STRING, description: "Detailed explanation of why this is a risk." }
              },
              required: ["name", "description", "risk", "rationale"]
            }
          }
        },
        required: ["summary", "keyInsights", "threatLevel", "permissions"]
      }
    }
  });

  try {
    const textOut = response.text || '{}';
    return JSON.parse(textOut);
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    return null;
  }
};

export const chatWithDoc = async (history: { role: 'user' | 'model', parts: { text: string }[] }[], query: string, context: string) => {
  const chat = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: `You are the Sentient-X Intelligence Officer. You are an expert in National Security Architectures, Android manifest permissions, and network protocols. Answer all questions with technical depth and a professional, slightly cold tone. Use data from the context document.`
    }
  });

  const result = await chat.sendMessage({ message: query });
  return result.text;
};

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { ArchitectureNode, ArchitectureLink } from '../types';

interface NetworkGraphProps {
  nodes: ArchitectureNode[];
  links: ArchitectureLink[];
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ nodes, links }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const [hoveredNode, setHoveredNode] = useState<ArchitectureNode | null>(null);

  useEffect(() => {
    if (!svgRef.current || nodes.length === 0) return;

    const width = svgRef.current.clientWidth;
    const height = svgRef.current.clientHeight;

    // Load persisted positions
    const savedPositions = localStorage.getItem('sentient-x-graph-positions');
    const positionsMap = savedPositions ? JSON.parse(savedPositions) : {};

    const nodesWithPositions = nodes.map(node => {
      const saved = positionsMap[node.id];
      return {
        ...node,
        fx: saved ? saved.fx : null,
        fy: saved ? saved.fy : null
      };
    });

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const simulation = d3.forceSimulation<ArchitectureNode>(nodesWithPositions)
      .force("link", d3.forceLink<ArchitectureNode, ArchitectureLink>(links).id(d => d.id).distance(120))
      .force("charge", d3.forceManyBody().strength(-400))
      .force("center", d3.forceCenter(width / 2, height / 2))
      .force("collision", d3.forceCollide().radius(30));

    const link = svg.append("g")
      .attr("stroke", "#1e293b")
      .attr("stroke-opacity", 0.8)
      .selectAll("line")
      .data(links)
      .join("line")
      .attr("stroke-width", d => Math.sqrt(d.value) * 2);

    const node = svg.append("g")
      .selectAll("circle")
      .data(nodesWithPositions)
      .join("circle")
      .attr("r", 10)
      .attr("class", "cursor-pointer transition-all duration-300")
      .attr("fill", d => d.group === 1 ? "#06b6d4" : d.group === 2 ? "#10b981" : "#f43f5e")
      .attr("filter", "drop-shadow(0 0 8px rgba(6, 182, 212, 0.4))")
      .on("mouseover", (event, d) => setHoveredNode(d))
      .on("mouseout", () => setHoveredNode(null))
      .call(d3.drag<SVGCircleElement, ArchitectureNode>()
        .on("start", dragstarted)
        .on("drag", dragged)
        .on("end", dragended));

    const labels = svg.append("g")
      .selectAll("text")
      .data(nodesWithPositions)
      .join("text")
      .text(d => d.label)
      .attr("font-size", "10px")
      .attr("class", "font-mono pointer-events-none")
      .attr("fill", "#94a3b8")
      .attr("dx", 14)
      .attr("dy", 4);

    simulation.on("tick", () => {
      link
        .attr("x1", d => (d.source as any).x)
        .attr("y1", d => (d.source as any).y)
        .attr("x2", d => (d.target as any).x)
        .attr("y2", d => (d.target as any).y);

      node
        .attr("cx", d => (d as any).x)
        .attr("cy", d => (d as any).y);

      labels
        .attr("x", d => (d as any).x)
        .attr("y", d => (d as any).y);
    });

    function dragstarted(event: any) {
      if (!event.active) simulation.alphaTarget(0.3).restart();
      event.subject.fx = event.subject.x;
      event.subject.fy = event.subject.y;
    }

    function dragged(event: any) {
      event.subject.fx = event.x;
      event.subject.fy = event.y;
    }

    function dragended(event: any) {
      if (!event.active) simulation.alphaTarget(0);
      // Persist on drag end
      const currentPositions = nodesWithPositions.reduce((acc, n: any) => {
        acc[n.id] = { fx: n.fx, fy: n.fy };
        return acc;
      }, {} as any);
      localStorage.setItem('sentient-x-graph-positions', JSON.stringify(currentPositions));
    }

    return () => {
      simulation.stop();
    };
  }, [nodes, links]);

  const clearPersistence = () => {
    localStorage.removeItem('sentient-x-graph-positions');
    window.location.reload();
  };

  return (
    <div className="w-full h-full bg-slate-950 rounded-xl overflow-hidden border border-slate-800 relative">
      <svg ref={svgRef} className="w-full h-full" />

      {/* Node Info Card */}
      {hoveredNode && (
        <div className="absolute top-4 right-4 w-64 bg-slate-900/90 border border-cyan-500/50 p-4 rounded-lg shadow-2xl backdrop-blur-md pointer-events-none z-10 animate-in fade-in slide-in-from-right-2">
          <h4 className="font-bold text-cyan-400 text-sm mb-1 uppercase tracking-wider">{hoveredNode.label}</h4>
          <p className="text-[10px] text-slate-400 font-mono mb-2">GROUP: {hoveredNode.group === 1 ? 'NEURAL' : hoveredNode.group === 2 ? 'KINETIC' : 'DATA'}</p>
          <p className="text-xs text-slate-300 leading-relaxed italic">"{hoveredNode.description}"</p>
        </div>
      )}

      {/* Control Overlay */}
      <div className="absolute bottom-4 left-4 flex space-x-2">
        <button 
          onClick={clearPersistence}
          className="bg-slate-800 hover:bg-slate-700 text-slate-400 text-[10px] font-mono px-3 py-1 rounded border border-slate-700 transition-colors"
        >
          RESET LAYOUT
        </button>
      </div>
    </div>
  );
};

