import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeDocument = async (text: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze the following document and provide a structured summary. 
    Crucially, for every technical permission mentioned (like Android manifest permissions), provide a detailed risk rationale explaining the threat vector it enables within this national security context.

    Document:
    ${text}
    `,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          keyInsights: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          },
          threatLevel: { 
            type: Type.STRING, 
            description: "Assess as Low, Medium, High, or Critical" 
          },
          permissions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                risk: { type: Type.STRING },
                rationale: { type: Type.STRING, description: "Detailed explanation of why this is a risk." }
              },
              required: ["name", "description", "risk", "rationale"]
            }
          }
        },
        required: ["summary", "keyInsights", "threatLevel", "permissions"]
      }
    }
  });

  try {
    const textOut = response.text || '{}';
    return JSON.parse(textOut);
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    return null;
  }
};

export const chatWithDoc = async (history: { role: 'user' | 'model', parts: { text: string }[] }[], query: string, context: string) => {
  // Use gemini-3-pro-preview for complex reasoning and search grounding if query looks like OSINT
  const isSearchQuery = query.toLowerCase().includes('search') || query.toLowerCase().includes('who is') || query.toLowerCase().includes('status of');

  const response = await ai.models.generateContent({
    model: isSearchQuery ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: `System: You are the Sentient-X Intelligence Officer. Context: ${context.slice(0, 5000)}` },
        ...history.map(h => ({ text: `${h.role === 'user' ? 'Operator' : 'AI'}: ${h.parts[0].text}` })),
        { text: `Operator: ${query}` }
      ]
    },
    config: {
      tools: isSearchQuery ? [{ googleSearch: {} }] : undefined,
    },
  });

  let text = response.text || '';

  // Extract URLs if search grounding was used
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    const urls = chunks
      .map((c: any) => c.web?.uri)
      .filter((u: string) => u);
    if (urls.length > 0) {
      text += "\n\n**Sources Analyzed:**\n" + urls.map((u: string) => `- [${u}](${u})`).join('\n');
    }
  }

  return text;
};

export const performForensicScan = async (query: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Perform a deep forensic OSINT analysis on the following target/query: "${query}". 
    Investigate potential links to .mil, .gov, or infrastructure patterns. 
    Format your response as highly technical intelligence data.`,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  return {
    text: response.text,
    sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((c: any) => c.web) || []
  };
};

