import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { ArchitectureNode, ArchitectureLink } from '../types';

interface NetworkGraphProps {
  nodes: ArchitectureNode[];
  links: ArchitectureLink[];
}

const NetworkGraph: React.FC<NetworkGraphProps> = ({ nodes, links }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const [hoveredNode, setHoveredNode] = useState<ArchitectureNode | null>(null);

  useEffect(() => {
    if (!svgRef.current || nodes.length === 0) return;

    const width = svgRef.current.clientWidth;
    const height = svgRef.current.clientHeight;

    const savedPositions = localStorage.getItem('sentient-x-graph-positions');
    const positionsMap = savedPositions ? JSON.parse(savedPositions) : {};

    const nodesWithPositions = nodes.map(node => {
      const saved = positionsMap[node.id];
      return {
        ...node,
        fx: saved ? saved.fx : null,
        fy: saved ? saved.fy : null
      };
    });

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const container = svg.append("g");

    const simulation = d3.forceSimulation<ArchitectureNode>(nodesWithPositions)
      .force("link", d3.forceLink<ArchitectureNode, ArchitectureLink>(links).id(d => d.id).distance(150))
      .force("charge", d3.forceManyBody().strength(-800))
      .force("center", d3.forceCenter(width / 2, height / 2))
      .force("collision", d3.forceCollide().radius(60));

    const link = container.append("g")
      .attr("stroke", "#1e293b")
      .attr("stroke-opacity", 0.6)
      .selectAll("line")
      .data(links)
      .join("line")
      .attr("stroke-width", d => Math.sqrt(d.value) * 3)
      .attr("stroke-dasharray", "4,2");

    const node = container.append("g")
      .selectAll("circle")
      .data(nodesWithPositions)
      .join("circle")
      .attr("r", 14)
      .attr("class", "cursor-crosshair transition-all duration-500")
      .attr("fill", d => d.group === 1 ? "#06b6d4" : d.group === 2 ? "#10b981" : "#f43f5e")
      .attr("stroke", "#020617")
      .attr("stroke-width", 3)
      .attr("filter", d => `drop-shadow(0 0 12px ${d.group === 1 ? 'rgba(6,182,212,0.6)' : d.group === 2 ? 'rgba(16,185,129,0.6)' : 'rgba(244,63,94,0.6)'})`)
      .on("mouseover", (event, d) => {
        setHoveredNode(d);
        d3.select(event.currentTarget).transition().attr("r", 18).attr("stroke-width", 5);
      })
      .on("mouseout", (event) => {
        setHoveredNode(null);
        d3.select(event.currentTarget).transition().attr("r", 14).attr("stroke-width", 3);
      })
      .call(d3.drag<SVGCircleElement, ArchitectureNode>()
        .on("start", dragstarted)
        .on("drag", dragged)
        .on("end", dragended));

    const labels = container.append("g")
      .selectAll("text")
      .data(nodesWithPositions)
      .join("text")
      .text(d => d.label)
      .attr("font-size", "10px")
      .attr("class", "font-mono font-black pointer-events-none uppercase tracking-widest")
      .attr("fill", "#64748b")
      .attr("dx", 24)
      .attr("dy", 5);

    simulation.on("tick", () => {
      link
        .attr("x1", d => (d.source as any).x)
        .attr("y1", d => (d.source as any).y)
        .attr("x2", d => (d.target as any).x)
        .attr("y2", d => (d.target as any).y);

      node
        .attr("cx", d => (d as any).x)
        .attr("cy", d => (d as any).y);

      labels
        .attr("x", d => (d as any).x)
        .attr("y", d => (d as any).y);
    });

    function dragstarted(event: any) {
      if (!event.active) simulation.alphaTarget(0.3).restart();
      event.subject.fx = event.subject.x;
      event.subject.fy = event.subject.y;
    }

    function dragged(event: any) {
      event.subject.fx = event.x;
      event.subject.fy = event.y;
    }

    function dragended(event: any) {
      if (!event.active) simulation.alphaTarget(0);
      const currentPositions = nodesWithPositions.reduce((acc, n: any) => {
        acc[n.id] = { fx: n.fx, fy: n.fy };
        return acc;
      }, {} as any);
      localStorage.setItem('sentient-x-graph-positions', JSON.stringify(currentPositions));
    }

    return () => { simulation.stop(); };
  }, [nodes, links]);

  return (
    <div className="w-full h-full relative group/graph">
      <svg ref={svgRef} className="w-full h-full" />

      {/* Interactive Tooltip Panel */}
      {hoveredNode && (
        <div className="absolute top-8 right-8 w-72 bg-slate-900/90 border border-cyan-500/40 p-6 rounded-[32px] shadow-[0_30px_60px_rgba(0,0,0,0.6)] backdrop-blur-xl pointer-events-none z-[200] animate-in fade-in slide-in-from-right-4 duration-300">
          <div className="flex items-center justify-between mb-4">
             <h4 className="font-black text-white text-sm uppercase tracking-widest italic">{hoveredNode.label}</h4>
             <div className={`w-3 h-3 rounded-full animate-pulse ${hoveredNode.group === 1 ? 'bg-cyan-500' : hoveredNode.group === 2 ? 'bg-emerald-500' : 'bg-rose-500'}`}></div>
          </div>
          <div className="space-y-4">
            <div>
              <p className="text-[9px] text-slate-500 font-mono font-black uppercase mb-1 tracking-widest">Enclave Group</p>
              <p className="text-[10px] text-slate-300 font-mono font-bold uppercase">
                {hoveredNode.group === 1 ? 'Neural / Cognitive' : hoveredNode.group === 2 ? 'Kinetic / Physical' : 'Intelligence / Data'}
              </p>
            </div>
            <div>
              <p className="text-[9px] text-slate-500 font-mono font-black uppercase mb-1 tracking-widest">Functional Scope</p>
              <p className="text-xs text-slate-400 leading-relaxed font-light italic">"{hoveredNode.description}"</p>
            </div>
            <div className="pt-2 border-t border-slate-800 flex justify-between items-center text-[8px] font-mono text-cyan-600/50 uppercase tracking-widest">
              <span>Node ID: {hoveredNode.id}</span>
              <span>Status: Synchronized</span>
            </div>
          </div>
        </div>
      )}

      {/* Persistence Reset */}
      <div className="absolute bottom-8 right-8">
        <button 
          onClick={() => { localStorage.removeItem('sentient-x-graph-positions'); window.location.reload(); }}
          className="bg-slate-900/80 hover:bg-slate-800 text-[9px] font-black text-slate-500 hover:text-cyan-400 px-4 py-2 rounded-xl border border-slate-800 hover:border-cyan-500/30 transition-all uppercase tracking-widest backdrop-blur-md"
        >
          Reset Mapping
        </button>
      </div>
    </div>
  );
};

