      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            keyInsights: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            threatLevel: { 
              type: Type.STRING, 
              description: "Assess as Low, Medium, High, or Critical" 
            },
            permissions: {
              type: Type.ARRAY,
              items: {
